// src/dm-session/application/use-cases/initialize-dm-session.use-case.ts
var InitializeDmSessionUseCase = class {
  constructor(sessionRepo, turnRepo, modelProviders) {
    this.sessionRepo = sessionRepo;
    this.turnRepo = turnRepo;
    this.modelProviders = modelProviders;
  }
  static {
    __name(this, "InitializeDmSessionUseCase");
  }
  async execute(dto) {
    const session = await this.sessionRepo.findById(UUID.fromString(dto.sessionId));
    if (!session) return Result.fail("DM_SESSION_NOT_FOUND" /* NOT_FOUND */);
    if (!session.isOwnedBy(dto.userId) && !dto.isAdmin) {
      return Result.fail("DM_SESSION_UNAUTHORIZED" /* UNAUTHORIZED */);
    }
    if (session.status !== "initializing") {
      return Result.fail("DM_SESSION_NOT_INITIALIZING" /* NOT_INITIALIZING */);
    }
    const provider = this.modelProviders[session.architectureType];
    const stream = streamAndPersistTurn({
      session,
      role: "dm",
      request: {
        sessionId: session.id.toString(),
        architectureType: session.architectureType,
        modelId: session.modelId,
        campaignPrompt: session.campaignPrompt,
        characters: session.characters,
        conversationHistory: [],
        playerInput: null,
        currentMemorySnapshot: session.memorySnapshot
      },
      provider,
      sessionRepo: this.sessionRepo,
      turnRepo: this.turnRepo
    });
    return Result.ok(stream);
  }
};

