function avatarRoutes(container) {
  const app2 = new Hono2();
  app2.post("/me/avatar", async (c) => {
    const user = await requireUser2(c);
    const formData = await c.req.formData();
    const file2 = formData.get("file");
    if (!file2) return c.json({ message: "Missing file" }, 400);
    const MAX_SIZE = 5 * 1024 * 1024;
    if (file2.size > MAX_SIZE) return c.json({ message: "File too large (max 5MB)" }, 413);
    const ALLOWED_TYPES = ["image/jpeg", "image/png", "image/webp", "image/gif"];
    if (!ALLOWED_TYPES.includes(file2.type)) {
      return c.json({ message: "Invalid file type. Only JPEG, PNG, WEBP and GIF are allowed." }, 400);
    }
    const token = c.req.header("authorization")?.split(" ")[1] ?? "";
    try {
      const avatarUrl = await uploadAvatar(c.env, user.id, file2, token);
      await container.updateUserProfileUseCase.execute({ userId: user.id, avatarUrl });
      return c.json({ message: "Avatar updated successfully", avatarUrl });
    } catch (e) {
      return c.json({ message: e.message || "Internal server error" }, 500);
    }
  });
  return app2;
}
